INSERT INTO public.domains (code, name, description) VALUES ('D01', 'Customer Service & Frontline Experience', 'Owns direct guest, passenger, and visitor contact moments where identity, arrival, service information, issue intake, and service recovery are handled.');
INSERT INTO public.domains (code, name, description) VALUES ('D02', 'Accommodation & Facilities Operations', 'Owns lodging, room readiness, housekeeping, property turnover, on-site facilities support, and wellness/leisure service readiness within hospitality accommodation settings.');
INSERT INTO public.domains (code, name, description) VALUES ('D03', 'Food, Beverage & Event Service Operations', 'Owns restaurant, kitchen, catering, banquet, venue, and business-event service work where food service, event coordination, and venue/vendor operations are the central work area.');
INSERT INTO public.domains (code, name, description) VALUES ('D04', 'Transport Movement & Passenger Operations', 'Owns operational movement of people across air, rail, road, cruise, ferry, and related passenger-service environments.');
INSERT INTO public.domains (code, name, description) VALUES ('D05', 'Travel Booking, Distribution & Agency Operations', 'Owns commercial travel reservation, package, itinerary, supplier coordination, OTA connectivity, and travel technology operations.');
INSERT INTO public.domains (code, name, description) VALUES ('D06', 'Destination, Attraction & Cultural Experience Management', 'Owns destination interpretation, tourism information, heritage and attraction experience, visitor facilitation, destination content, and tourism data signals used to frame visitor experience.');
INSERT INTO public.domains (code, name, description) VALUES ('D07', 'Safety, Compliance & Sustainable Tourism Governance', 'Owns evidence-backed tourism safety, regulatory compliance, medical/wellness travel coordination, sustainability, community/rural tourism governance, and risk control structures.');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-01', 'Verify guest and visitor arrival readiness through identity, booking, and service handoff evidence', 'Perform front-contact arrival checks by validating identity, reservation or visitor request evidence, resolving mismatches, and releasing the correct service handoff.', 1, 'Core', ARRAY['Social'], ARRAY['Conventional', 'Enterprising'], 'high-contact guest interaction with structured reservation, ID, room-status, and handoff accuracy');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-02', 'Route passengers through terminal assistance, queue control, and disruption communication', 'Guide passenger-facing terminal movement by checking assistance needs, queue context, and delay information, then issuing the correct routing or support handoff.', 2, 'Important', ARRAY['Social'], ARRAY['Conventional', 'Realistic'], 'passenger-facing routing, queue observation, disruption communication, and safe escalation using terminal evidence');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-03', 'Resolve service recovery, complaint, refund, and claim cases through evidence-based closure', 'Classify guest or passenger service issues, assemble recovery or claim evidence, escalate exceptions, and close the case with documented outcome confirmation.', 3, 'Core', ARRAY['Social'], ARRAY['Conventional', 'Enterprising'], 'calm complaint handling, empathetic recovery communication, evidence-based escalation, and disciplined closure tracking');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-04', 'Release rooms through cleaning, readiness inspection, and defect correction evidence', 'Control room-readiness outcomes by checking cleaning status, amenity condition, defect evidence, and final release confirmation before guest use.', 4, 'Core', ARRAY['Conventional'], ARRAY['Realistic'], 'structured inspection discipline, physical environment awareness, defect logging, and reliable room-release follow-through');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-05', 'Prepare alternative stays and property handoffs through host readiness and guest issue control', 'Coordinate homestay, hostel, serviced-apartment, or rental property readiness by confirming turnover evidence, host availability, and issue handoff closure.', 5, 'Important', ARRAY['Realistic'], ARRAY['Conventional'], 'structured property readiness, host/guest communication, handoff discipline, and reliable issue-closure follow-through');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-06', 'Coordinate wellness, leisure, valet, and facility service handoffs through appointment and readiness evidence', 'Prepare leisure or wellness service delivery by checking appointment, facility, or valet context, allocating resources, and confirming the service handoff.', 6, 'Important', ARRAY['Conventional'], ARRAY['Realistic', 'Enterprising'], 'empathetic service coordination, sensitive document handling, appointment discipline, and calm recovery-stay issue escalation');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-07', 'Control dining orders and bill settlement through table, KOT, POS, and payment evidence', 'Execute F&B service transactions by validating table/order details, station constraints, bill postings, payment evidence, and guest-facing settlement closure.', 7, 'Core', ARRAY['Social'], ARRAY['Conventional', 'Realistic'], 'guest-facing service energy combined with accurate KOT/POS handling, station coordination, and payment closure discipline; hands-on production discipline, timing control, hygiene compliance, station coordination, and calm dispatch under pressure');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-08', 'Control kitchen production and dispatch through preparation, packaging, and handoff evidence', 'Coordinate kitchen or cloud-kitchen execution by tracking preparation status, dispatch requirements, packaging evidence, and delivery handoff readiness.', 8, 'Important', ARRAY['Realistic'], ARRAY['Conventional', 'Social'], 'hands-on production discipline, timing control, hygiene compliance, station coordination, and calm dispatch under pressure');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-09', 'Run banquet and venue service operations through event setup, service run, and closure evidence', 'Translate event requirements into banquet setup, venue readiness, service execution, exception control, and post-service handoff evidence.', 9, 'Important', ARRAY['Realistic'], ARRAY['Conventional', 'Social', 'Enterprising'], 'hands-on event setup, live service flow, timing control, venue closure checks, and evidence-based handoff');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-10', 'Coordinate MICE event briefs, stakeholder alignment, venue logistics, and post-event closure', 'Convert MICE briefs into aligned logistics, vendor or venue coordination, stakeholder handoffs, and documented post-event closure.', 10, 'Important', ARRAY['Enterprising'], ARRAY['Social', 'Conventional'], 'guest-facing service energy combined with accurate KOT/POS handling, station coordination, and payment closure discipline');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-11', 'Control air passenger check-in, baggage acceptance, boarding, and load documentation', 'Process air passengers by validating PNR, baggage, seat and manifest evidence, resolving boarding or load exceptions, and releasing flight documentation.', 11, 'Important', ARRAY['Conventional'], ARRAY['Social', 'Realistic'], 'structured check-in, baggage acceptance, boarding control, load documentation, and regulated exception escalation');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-12', 'Support rail booking, refund, station information, and disruption response through passenger evidence', 'Handle rail passenger service needs by checking ticket or refund evidence, disruption context, station information, and final passenger communication.', 12, 'Important', ARRAY['Conventional'], ARRAY['Social', 'Realistic'], 'structured rail booking/refund documentation, passenger communication, station-information accuracy, and calm disruption handling');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-13', 'Control road mobility, vehicle rental inspection, fleet dispatch, and trip completion evidence', 'Manage road travel operations by validating vehicle condition, driver or rider assignment, trip constraints, return evidence, and completion closure.', 13, 'Important', ARRAY['Realistic'], ARRAY['Conventional', 'Social'], 'hands-on production discipline, timing control, hygiene compliance, station coordination, and calm dispatch under pressure');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-14', 'Control ferry, cruise, manifest, boarding, and shore-excursion passenger handoffs', 'Process water-transport passengers by checking manifest records, boarding eligibility, excursion handoff details, and safety or return exceptions.', 14, 'Optional', ARRAY['Realistic'], ARRAY['Conventional'], 'passenger movement control, manifest accuracy, physical boarding coordination, and calm disruption handling');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-15', 'Create, confirm, change, and refund bookings through reservation and ticketing evidence', 'Manage booking support outcomes by creating or modifying records, validating fare or cancellation rules, and confirming customer-ready ticketing closure.', 15, 'Core', ARRAY['Conventional'], ARRAY['Social', 'Enterprising'], 'calm complaint handling, empathetic recovery communication, evidence-based escalation, and disciplined closure tracking; structured booking documentation, passenger communication, refund/change accuracy, and calm disruption handling');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-16', 'Coordinate itinerary suppliers, tour departure files, and traveler handoff readiness', 'Prepare tour packages by confirming supplier commitments, itinerary constraints, traveler documentation, departure file readiness, and handoff closure.', 16, 'Important', ARRAY['Conventional'], ARRAY['Enterprising', 'Social'], 'structured booking documentation, passenger communication, refund/change accuracy, and calm disruption handling');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-17', 'Stabilize OTA inventory, fare synchronization, API booking errors, and supplier handoffs', 'Operate travel technology workflows by checking extranet or API evidence, reconciling availability/fare mismatches, and handing off supplier-side corrections.', 17, 'Important', ARRAY['Enterprising'], ARRAY['Conventional', 'Investigative'], 'record accuracy, error-trace discipline, supplier coordination, and calm handling of booking or API disruption');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-18', 'Align partner rates, allotments, commercial proposals, and distribution handoffs', 'Control commercial distribution coordination by validating partner terms, allotment or rate evidence, proposal requirements, and downstream handoff records.', 18, 'Optional', ARRAY['Social'], ARRAY['Enterprising', 'Conventional'], 'guest-facing service energy combined with accurate KOT/POS handling, station coordination, and payment closure discipline');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-19', 'Convert tourism data, visitor signals, and program evidence into destination reporting', 'Collect and verify tourism planning inputs, visitor data, and content/program evidence so destination teams can report and update demand signals.', 19, 'Important', ARRAY['Investigative'], ARRAY['Artistic', 'Conventional'], 'analytical interpretation, structured reporting, curiosity about destination patterns, and evidence-based planning judgment');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-20', 'Manage heritage attraction visitor flow, interpretation, and safety handoffs', 'Operate cultural or heritage visitor experiences by controlling ticketed flow, guide interpretation context, route constraints, and visitor safety closure.', 20, 'Important', ARRAY['Social'], ARRAY['Artistic', 'Investigative'], 'visitor interaction, cultural storytelling, route clarity, empathy, and flexible handling of visitor questions');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-21', 'Facilitate pilgrimage, cultural, and festival visitor journeys through guide and route evidence', 'Support religious or cultural visitor movement by confirming circuit/guide context, visitor needs, crowd or timing constraints, and service handoff outcomes.', 21, 'Important', ARRAY['Social'], ARRAY['Conventional', 'Artistic'], 'visitor interaction, cultural storytelling, route clarity, empathy, and flexible handling of visitor questions');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-22', 'Deliver private, VIP, and digital tourism experiences through preference, content, and disruption control', 'Translate premium or digital experience requests into itinerary, interpretation, concierge, or recovery actions with documented service closure.', 22, 'Optional', ARRAY['Social'], ARRAY['Enterprising', 'Artistic', 'Conventional'], 'high-touch preference handling, VIP privacy, digital content coordination, and disruption recovery within role boundaries');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-23', 'Control adventure activity registration, safety briefing, incident escalation, and field return', 'Execute adventure-tourism field operations by validating participant evidence, route/activity readiness, safety briefings, incident escalation, and return confirmation.', 23, 'Core', ARRAY['Conventional'], ARRAY['Realistic', 'Social'], 'field-safety awareness, visitor guidance, calm incident response, structured briefing, and evidence-based safety closure');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-24', 'Coordinate safari dispatch, guide briefing, vehicle breakdown response, and tourist rescue closure', 'Manage wildlife and safari operations by checking vehicle/guide evidence, dispatch readiness, breakdown escalation, rescue handoff, and tourist safety closure.', 24, 'Important', ARRAY['Social'], ARRAY['Conventional', 'Investigative'], 'field-safety awareness, visitor guidance, calm vehicle-breakdown response, structured dispatch, and evidence-based rescue handoff');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-25', 'Coordinate medical, wellness, and AYUSH travel journeys through provider, appointment, and stay evidence', 'Align patient or wellness traveler journeys by validating appointment, travel window, provider note, stay requirement, and recovery or program handoff evidence.', 25, 'Important', ARRAY['Conventional'], ARRAY['Social', 'Investigative'], 'empathetic patient or wellness-guest coordination, sensitive document handling, appointment discipline, and calm recovery-stay issue escalation');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-26', 'Govern eco-site visitor conduct, conservation checks, sustainability evidence, and community benefit records', 'Control responsible tourism operations by checking visitor conduct, conservation requirements, sustainability records, and community-benefit evidence.', 26, 'Optional', ARRAY['Investigative'], ARRAY['Conventional', 'Enterprising'], 'structured compliance checking, conservation discipline, community sensitivity, and evidence-based responsible-tourism follow-through');
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('IND-CAP-27', 'Manage rural community, homestay, craft, and livelihood experience operations through compliance and host evidence', 'Coordinate rural and community tourism experiences by validating host or artisan availability, visitor profile, compliance evidence, payment record, and visit closure.', 27, 'Important', ARRAY['Investigative'], ARRAY['Artistic', 'Conventional'], 'visitor interaction, cultural storytelling, route clarity, empathy, and flexible handling of visitor questions; community-facing empathy, cultural openness, structured visit coordination, and careful livelihood evidence handling');
