INSERT INTO public.occupations (code, name, description, primary_riasec, secondary_riasec, tertiary_riasec, riasec_code_string, primary_weight, secondary_weight, tertiary_weight, riasec_reason, observable_behaviours, work_context_summary, estimated_plan_weeks, fitment_category, fitment_confidence, is_active) VALUES ('HTT-ROLE-076', 'Deckhand', 'Supports ferry/cruise passenger movement through manifest, boarding, safety and excursion handoffs. Recommended RIASEC profile: RSC.', 'R', 'S', 'C', 'RSC', 0.5, 0.3, 0.2, 'Deckhand is mapped to RSC because it performs physical/service operations with safety, customer handoff and record discipline through direct role tasks and evidence outputs.', 'Checks manifests, supports boarding, monitors safety exceptions, coordinates excursion handoffs.', 'Transport Movement & Passenger Operations role requiring live service coordination and documented output.', 14, ARRAY['Supporting Fit'], ARRAY['Low'], TRUE);
INSERT INTO public.occupations (code, name, description, primary_riasec, secondary_riasec, tertiary_riasec, riasec_code_string, primary_weight, secondary_weight, tertiary_weight, riasec_reason, observable_behaviours, work_context_summary, estimated_plan_weeks, fitment_category, fitment_confidence, is_active) VALUES ('HTT-ROLE-077', 'Rail Ticketing / Refund Processing Clerk', 'Processes bills, refunds, ticketing or claims using rules, documentation and customer communication. Recommended RIASEC profile: CSR.', 'C', 'S', 'R', 'CSR', 0.5, 0.3, 0.2, 'Rail Ticketing / Refund Processing Clerk is mapped to CSR because it processes claims, tickets or refunds accurately with service awareness and procedure control through direct role tasks and evidence outputs.', 'Validates rules, processes payments/refunds, records exceptions, explains outcomes to customers.', 'Transport Movement & Passenger Operations role requiring live service coordination and documented output.', 14, ARRAY['Supporting Fit'], ARRAY['Low'], TRUE);
